import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface CourseProgressData {
  course: {
    name: string;
    completedModules: number;
    totalModules: number;
  };
  quizScores: {
    quiz: string;
    score: number;
  }[];
  timeSpentTrend: number[];
}

export default function Widget() {
  const data = response.data as CourseProgressData;
  const { course, quizScores, timeSpentTrend } = data;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 350,
        maxWidth: 500,
        bgcolor: '#1A202C',
        color: '#F7FAFC',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#38B2AC' }}>
              {course.name}
            </Typography>
            <Typography variant="body2">
              Modules Completed: {course.completedModules} / {course.totalModules}
            </Typography>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: timeSpentTrend,
                color: '#38B2AC',
                curve: 'linear',
                showMark: false,
              },
            ]}
            xAxis={[{ data: timeSpentTrend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack spacing={1.5}>
            {quizScores.slice(0, 3).map((quizScore, index) => (
              <Box key={index}>
                <Typography variant="body2" sx={{ color: '#E2E8F0' }}>
                  {quizScore.quiz}: <span style={{ fontWeight: 600 }}>{quizScore.score}%</span>
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
